from __future__ import annotations

import io
import os
import sqlite3
import threading
from collections import Counter, defaultdict
from datetime import datetime, timezone
from typing import Dict, List, Optional, Tuple

from fastapi import FastAPI, File, HTTPException, UploadFile
from pydantic import BaseModel, Field
from PIL import Image
import uvicorn

try:
    import numpy as np
    from sklearn.linear_model import LogisticRegression
    from sklearn.preprocessing import LabelEncoder
except Exception:
    np = None
    LogisticRegression = None
    LabelEncoder = None

app = FastAPI(title="Crowdsourced Data Labeling System", version="1.0.0")

DB_PATH = os.getenv("LABELING_DB_PATH", "labeling.db")
MODEL_PATH = os.getenv("MODEL_PATH", "model.pkl")
TRAIN_LIMIT = int(os.getenv("TRAIN_LIMIT", "0"))

db_lock = threading.Lock()
model_lock = threading.Lock()
model_state = {"model": None, "encoder": None}


def now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def get_conn() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    return conn


def init_db() -> None:
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS images (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                filename TEXT NOT NULL,
                content BLOB NOT NULL,
                created_at TEXT NOT NULL
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS labels (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                image_id INTEGER NOT NULL,
                annotator_id TEXT NOT NULL,
                label TEXT NOT NULL,
                created_at TEXT NOT NULL,
                FOREIGN KEY(image_id) REFERENCES images(id)
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS aggregated_labels (
                image_id INTEGER PRIMARY KEY,
                label TEXT NOT NULL,
                vote_count INTEGER NOT NULL,
                total_votes INTEGER NOT NULL,
                updated_at TEXT NOT NULL,
                FOREIGN KEY(image_id) REFERENCES images(id)
            )
            """
        )
        conn.commit()
        conn.close()


def image_to_features(content: bytes) -> Optional[List[float]]:
    try:
        img = Image.open(io.BytesIO(content)).convert("RGB")
        img = img.resize((32, 32))
        arr = np.asarray(img, dtype=np.float32) / 255.0
        return arr.flatten().tolist()
    except Exception:
        return None


def aggregate_image_labels(image_id: int) -> Optional[Tuple[str, int, int]]:
    with db_lock:
        conn = get_conn()
        rows = conn.execute(
            "SELECT label FROM labels WHERE image_id = ?",
            (image_id,),
        ).fetchall()
        if not rows:
            conn.close()
            return None
        counts = Counter(r["label"] for r in rows)
        top_label, top_count = counts.most_common(1)[0]
        total_votes = len(rows)
        conn.execute(
            """
            INSERT INTO aggregated_labels (image_id, label, vote_count, total_votes, updated_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(image_id) DO UPDATE SET
                label=excluded.label,
                vote_count=excluded.vote_count,
                total_votes=excluded.total_votes,
                updated_at=excluded.updated_at
            """,
            (image_id, top_label, top_count, total_votes, now_iso()),
        )
        conn.commit()
        conn.close()
        return top_label, top_count, total_votes


def get_labeled_training_data() -> Tuple[List[List[float]], List[str]]:
    with db_lock:
        conn = get_conn()
        rows = conn.execute(
            """
            SELECT i.content AS content, a.label AS label
            FROM aggregated_labels a
            JOIN images i ON i.id = a.image_id
            ORDER BY i.id ASC
            """
        ).fetchall()
        conn.close()

    X: List[List[float]] = []
    y: List[str] = []
    for row in rows:
        feats = image_to_features(row["content"])
        if feats is not None:
            X.append(feats)
            y.append(row["label"])
    return X, y


def train_model() -> Dict[str, object]:
    if np is None or LogisticRegression is None or LabelEncoder is None:
        raise RuntimeError("Required ML dependencies are not installed")

    X, y = get_labeled_training_data()
    if not X:
        raise RuntimeError("No labeled data available for training")

    if TRAIN_LIMIT > 0:
        X = X[:TRAIN_LIMIT]
        y = y[:TRAIN_LIMIT]

    encoder = LabelEncoder()
    y_enc = encoder.fit_transform(y)
    X_np = np.asarray(X, dtype=np.float32)

    model = LogisticRegression(max_iter=1000, n_jobs=None)
    model.fit(X_np, y_enc)

    with model_lock:
        model_state["model"] = model
        model_state["encoder"] = encoder

    try:
        import pickle

        with open(MODEL_PATH, "wb") as f:
            pickle.dump({"model": model, "encoder": encoder}, f)
    except Exception:
        pass

    return {"trained_on": len(X), "classes": list(encoder.classes_)}


class LabelIn(BaseModel):
    image_id: int = Field(..., ge=1)
    annotator_id: str = Field(..., min_length=1)
    label: str = Field(..., min_length=1)


@app.on_event("startup")
def on_startup() -> None:
    init_db()
    try:
        import pickle

        if os.path.exists(MODEL_PATH):
            with open(MODEL_PATH, "rb") as f:
                obj = pickle.load(f)
            with model_lock:
                model_state["model"] = obj.get("model")
                model_state["encoder"] = obj.get("encoder")
    except Exception:
        pass


@app.post("/images")
async def upload_image(file: UploadFile = File(...)):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")

    try:
        Image.open(io.BytesIO(content)).verify()
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")

    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            "INSERT INTO images (filename, content, created_at) VALUES (?, ?, ?)",
            (file.filename or "image", content, now_iso()),
        )
        image_id = cur.lastrowid
        conn.commit()
        conn.close()

    return {"image_id": image_id, "filename": file.filename}


@app.post("/labels")
def submit_label(payload: LabelIn):
    with db_lock:
        conn = get_conn()
        image = conn.execute("SELECT id FROM images WHERE id = ?", (payload.image_id,)).fetchone()
        if not image:
            conn.close()
            raise HTTPException(status_code=404, detail="Image not found")

        conn.execute(
            """
            INSERT INTO labels (image_id, annotator_id, label, created_at)
            VALUES (?, ?, ?, ?)
            """,
            (payload.image_id, payload.annotator_id, payload.label, now_iso()),
        )
        conn.commit()
        conn.close()

    result = aggregate_image_labels(payload.image_id)
    if not result:
        return {"status": "saved", "aggregated": None}

    label, vote_count, total_votes = result
    return {
        "status": "saved",
        "aggregated": {
            "image_id": payload.image_id,
            "label": label,
            "vote_count": vote_count,
            "total_votes": total_votes,
        },
    }


@app.get("/images/{image_id}/labels")
def get_image_labels(image_id: int):
    with db_lock:
        conn = get_conn()
        rows = conn.execute(
            """
            SELECT annotator_id, label, created_at
            FROM labels
            WHERE image_id = ?
            ORDER BY created_at ASC, id ASC
            """,
            (image_id,),
        ).fetchall()
        agg = conn.execute(
            "SELECT label, vote_count, total_votes, updated_at FROM aggregated_labels WHERE image_id = ?",
            (image_id,),
        ).fetchone()
        conn.close()

    if not rows and not agg:
        raise HTTPException(status_code=404, detail="Image or labels not found")

    return {
        "image_id": image_id,
        "labels": [
            {"annotator_id": r["annotator_id"], "label": r["label"], "created_at": r["created_at"]}
            for r in rows
        ],
        "aggregated": None
        if agg is None
        else {
            "label": agg["label"],
            "vote_count": agg["vote_count"],
            "total_votes": agg["total_votes"],
            "updated_at": agg["updated_at"],
        },
    }


@app.post("/aggregate/{image_id}")
def aggregate(image_id: int):
    result = aggregate_image_labels(image_id)
    if not result:
        raise HTTPException(status_code=404, detail="No labels for image")
    label, vote_count, total_votes = result
    return {
        "image_id": image_id,
        "label": label,
        "vote_count": vote_count,
        "total_votes": total_votes,
    }


@app.post("/train")
def train():
    return train_model()


@app.get("/model/status")
def model_status():
    with model_lock:
        model_loaded = model_state["model"] is not None
        classes = None
        if model_loaded and model_state["encoder"] is not None:
            try:
                classes = list(model_state["encoder"].classes_)
            except Exception:
                classes = None
    return {"model_loaded": model_loaded, "classes": classes}


@app.post("/predict/{image_id}")
def predict(image_id: int):
    with model_lock:
        model = model_state["model"]
        encoder = model_state["encoder"]

    if model is None or encoder is None:
        raise HTTPException(status_code=400, detail="Model not trained")

    with db_lock:
        conn = get_conn()
        row = conn.execute("SELECT content FROM images WHERE id = ?", (image_id,)).fetchone()
        conn.close()

    if row is None:
        raise HTTPException(status_code=404, detail="Image not found")

    feats = image_to_features(row["content"])
    if feats is None:
        raise HTTPException(status_code=400, detail="Unable to process image")

    if np is None:
        raise HTTPException(status_code=500, detail="Numpy unavailable")

    x = np.asarray([feats], dtype=np.float32)
    pred = model.predict(x)[0]
    label = encoder.inverse_transform([pred])[0]
    proba = None
    if hasattr(model, "predict_proba"):
        try:
            proba_arr = model.predict_proba(x)[0]
            proba = {encoder.inverse_transform([i])[0]: float(p) for i, p in enumerate(proba_arr)}
        except Exception:
            proba = None

    return {"image_id": image_id, "prediction": label, "probabilities": proba}


